const v = $input.first().json;
const gaps = v.gaps || [];
const conversas_ref = v.conversas_referencia || [];

const exemplos_txt = conversas_ref.map((c, i) =>
  `Exemplo ${i+1} (score ${c.score_qualidade}/10, ${c.tipo_venda}):\n  Argumentos eficazes: ${JSON.stringify(c.argumentos?.filter(a=>a.efetivo).map(a=>a.texto).slice(0,2))}\n  Padrão: ${c.padrao_detectado}`
).join('\n');

const objecoes_txt = (v.top_objecoes_sem_resposta || []).map(o =>
  `• ${o.tipo_objecao}: "${o.texto_objecao}" (${o.frequencia}x${o.sem_resposta_boa ? ' — SEM RESPOSTA BOA' : ''})`
).join('\n');

const prompt = `Você é um especialista em treinamento de equipes comerciais.

Crie um material de treinamento personalizado para o vendedor "${v.vendedor_nome}".

Contexto do vendedor:
- Tipo de venda com maior afinidade: ${v.tipo_venda_afinidade || 'não definido'}
- Taxa de conversão atual: ${v.taxa_conversao_media}%
- Gaps identificados:
${gaps.map(g => `  • ${g}`).join('\n')}

Objeções mais frequentes no período:
${objecoes_txt || 'Sem dados ainda'}

Exemplos de conversas de sucesso deste vendedor:
${exemplos_txt || 'Ainda sem exemplos suficientes'}

Gere um treinamento prático com esta estrutura JSON (sem markdown):
{
  "titulo": "Título específico e motivador do treinamento",
  "tipo_conteudo": "guia",
  "gap_principal_abordado": "gap que este treinamento resolve",
  "conteudo": {
    "objetivo": "O que o vendedor vai conseguir fazer após este treinamento",
    "fundamento": "Por que este gap impacta as vendas (dados específicos)",
    "tecnica": {
      "nome": "Nome da técnica recomendada",
      "passo_a_passo": [
        "Passo 1 específico",
        "Passo 2 específico",
        "Passo 3 específico"
      ]
    },
    "exemplos_campo": [
      {
        "situacao": "Situação real comum",
        "abordagem_recomendada": "O que dizer/fazer",
        "por_que_funciona": "Explicação"
      }
    ],
    "respostas_objecoes": [
      {
        "objecao": "Texto da objeção",
        "resposta_validada": "Resposta que já funcionou em campo"
      }
    ],
    "checklist_campo": [
      "Item para verificar antes de cada conversa",
      "Item durante",
      "Item após"
    ]
  }
}`;

return [{
  json: {
    vendedor_id:   v.vendedor_id,
    vendedor_nome: v.vendedor_nome,
    tipo_venda:    v.tipo_venda_afinidade,
    gaps:          v.gaps,
    conversas_referencia: (v.conversas_referencia || []).map(c => c.id),
    prompt
  }
}];

