const ctx = $('preparar-prompt-treino').first().json;
const claudeResponse = $input.first().json;

let treinamento;
try {
  const content = claudeResponse.content?.[0]?.text || '{}';
  treinamento = JSON.parse(content);
} catch(e) {
  treinamento = { titulo: 'Treinamento (erro ao gerar)', tipo_conteudo: 'guia', conteudo: {} };
}

return [{
  json: {
    vendedor_id:           ctx.vendedor_id,
    produto_nome:          null,
    tipo_venda:            ctx.tipo_venda,
    tipo_conteudo:         treinamento.tipo_conteudo || 'guia',
    titulo:                treinamento.titulo,
    conteudo:              treinamento.conteudo || {},
    baseado_em_gaps:       ctx.gaps,
    conversas_referencia:  ctx.conversas_referencia
  }
}];
